arguments.command:
$REPO = "edburns/Build26-BRK206-your-agent-anywhere-multiclient-multidevice-with-github-copilot-sdk"
$JTBDTASK_BRANCH = "copilot/dd-3017826-dynamic-ui-updates"
$PR_NUMBER = "21"

Write-Host "=== Step 1: Check for action_required runs ==="
$PENDING_RUNS = gh run list -R $REPO --branch "$JTBDTASK_BRANCH" `
  --json databaseId,conclusion,status,name `
  --jq '.[] | select(.conclusion == "action_required" or .status == "action_required") | .databaseId' 2>$null

Write-Host "Pending runs: $PENDING_RUNS"

if ($PENDING_RUNS) {
    foreach ($RUN_ID in ($PENDING_RUNS -split "`n" | Where-Object { $_ -match '\d+' })) {
        Write-Host "Approving run $RUN_ID..."
        gh run rerun $RUN_ID -R $REPO
    }
} else {
    Write-Host "No action_required runs found."
}

Write-Host ""
Write-Host "=== Current run status ==="
gh run list -R $REPO --branch "$JTBDTASK_BRANCH" --json databaseId,status,conclusion,name --jq '.[] | "\(.name): \(.status)/\(.conclusion)"'

